1	// Eligibility engine — shared between get-listing-detail and
2	// apply-to-listing (US-039 + US-041).
3	//
4	// Pre-conditions are evaluated against the creator's denormalized metrics
5	// from `creator_profiles`. Only pre-conditions gate apply-time eligibility
6	// per docs/tech-architecture.md §6.3. Post-conditions are returned by
7	// get-listing-detail for UI display and evaluated later on submissions.
8	//
9	// Fail-closed on missing metrics (§3d): when the creator hasn't been
10	// scraped yet (or a specific platform field is NULL), the pre-condition
11	// keyed on that field fails. Same rule extends to pre-condition rows with
12	// an unknown operator or unreadable metric — treat as failed rather than
13	// silently pass, so a future mis-migrated row can't flip a listing to
14	// eligible by accident.
15	
16	export type Platform = "tiktok" | "instagram";
17	export type ConditionKind = "pre" | "post";
18	
19	export interface ConditionRow {
20	  id: string;
21	  listing_version_id: string;
22	  kind: ConditionKind;
23	  metric: string;
24	  platform: Platform | null;
25	  operator: string;
26	  numeric_threshold: string | number | null;
27	  text_threshold: string | null;
28	  bool_threshold: boolean | null;
29	  created_at: string;
30	}
31	
32	export interface CreatorProfileRow {
33	  tiktok_follower_count: number | null;
34	  tiktok_avg_views_last_10: number | null;
35	  tiktok_total_likes: number | null;
36	  tiktok_video_count: number | null;
37	  tiktok_is_verified: boolean | null;
38	  instagram_follower_count: number | null;
39	  instagram_avg_views_last_10: number | null;
40	  instagram_media_count: number | null;
41	}
42	
43	export interface FailedCondition {
44	  metric: string;
45	  platform: Platform | null;
46	  required: number | boolean;
47	  actual: number | boolean | null;
48	}
49	
50	export const EMPTY_CREATOR_METRICS: CreatorProfileRow = {
51	  tiktok_follower_count: null,
52	  tiktok_avg_views_last_10: null,
53	  tiktok_total_likes: null,
54	  tiktok_video_count: null,
55	  tiktok_is_verified: null,
56	  instagram_follower_count: null,
57	  instagram_avg_views_last_10: null,
58	  instagram_media_count: null,
59	};
60	
61	// Evaluate a single pre-condition against the creator's denormalized
62	// metrics. Returns `null` on pass, or the failed-condition detail on fail.
63	// Missing data (null actual for a numeric threshold) fails closed per §3d.
64	export function evaluatePreCondition(
65	  condition: ConditionRow,
66	  metrics: CreatorProfileRow,
67	): FailedCondition | null {
68	  const { metric, platform, operator } = condition;
69	  if (operator === "gte") {
70	    const required = Number(condition.numeric_threshold);
71	    if (!Number.isFinite(required)) return null; // malformed row — skip, not fail
72	    const actual = readNumericMetric(metrics, platform, metric);
73	    if (actual === null || actual < required) {
74	      return { metric, platform, required, actual };
75	    }
76	    return null;
77	  }
78	  if (operator === "bool") {
79	    const required = condition.bool_threshold === true;
80	    const actual = readBoolMetric(metrics, platform, metric);
81	    if (actual !== required) {
82	      return { metric, platform, required, actual };
83	    }
84	    return null;
85	  }
86	  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
87	  // are reserved for post-conditions today (e.g. post_must_mention uses
88	  // 'contains'), so this branch should be unreachable; if a future migration
89	  // misplaces an operator, we'd rather block an apply than silently allow it.
90	  console.warn("pre-condition with unknown operator treated as failed", {
91	    condition_id: condition.id,
92	    operator,
93	    metric,
94	    platform,
95	  });
96	  const parsed = Number(condition.numeric_threshold);
97	  return {
98	    metric,
99	    platform,
100	    required: Number.isFinite(parsed) ? parsed : 0,
101	    actual: null,
102	  };
103	}
104	
105	// Evaluate every pre-condition and return the (possibly empty) list of
106	// failures. Post-conditions are ignored.
107	export function evaluatePreConditions(
108	  conditions: ConditionRow[],
109	  metrics: CreatorProfileRow,
110	): FailedCondition[] {
111	  const failed: FailedCondition[] = [];
112	  for (const c of conditions) {
113	    if (c.kind !== "pre") continue;
114	    const miss = evaluatePreCondition(c, metrics);
115	    if (miss) failed.push(miss);
116	  }
117	  return failed;
118	}
119	
120	function readNumericMetric(
121	  metrics: CreatorProfileRow,
122	  platform: Platform | null,
123	  metric: string,
124	): number | null {
125	  if (platform === "tiktok") {
126	    switch (metric) {
127	      case "min_followers":
128	        return metrics.tiktok_follower_count;
129	      case "min_avg_views_last_n":
130	        return metrics.tiktok_avg_views_last_10;
131	      case "min_total_likes":
132	        return metrics.tiktok_total_likes;
133	      case "min_videos_posted":
134	        return metrics.tiktok_video_count;
135	      default:
136	        return null;
137	    }
138	  }
139	  if (platform === "instagram") {
140	    switch (metric) {
141	      case "min_followers":
142	        return metrics.instagram_follower_count;
143	      case "min_avg_views_last_n":
144	        return metrics.instagram_avg_views_last_10;
145	      case "min_videos_posted":
146	        return metrics.instagram_media_count;
147	      default:
148	        return null;
149	    }
150	  }
151	  return null;
152	}
153	
154	function readBoolMetric(
155	  metrics: CreatorProfileRow,
156	  platform: Platform | null,
157	  metric: string,
158	): boolean | null {
159	  if (platform === "tiktok" && metric === "verified_only") {
160	    return metrics.tiktok_is_verified;
161	  }
162	  return null;
163	}
